<div class="row g-4 mb-4"><div class="col-md-4"><div class="admin-stat-card"><span class="stat-icon"><i class="fa-solid fa-comments"></i></span><div class="text-muted small">Total</div><div class="metric-value"><?= e((string) ($summary['total_feedbacks'] ?? 0)) ?></div></div></div><div class="col-md-4"><div class="admin-stat-card"><span class="stat-icon"><i class="fa-solid fa-bullhorn"></i></span><div class="text-muted small">Publicados</div><div class="metric-value"><?= e((string) ($summary['published_feedbacks'] ?? 0)) ?></div></div></div><div class="col-md-4"><div class="admin-stat-card"><span class="stat-icon"><i class="fa-solid fa-star"></i></span><div class="text-muted small">Média</div><div class="metric-value"><?= e(number_format((float) ($summary['average_rating'] ?? 0), 1)) ?></div></div></div></div>
<div class="admin-card mb-4"><form class="row g-3"><div class="col-md-5"><label class="form-label fw-semibold">Pesquisar</label><input type="text" name="q" class="form-control" value="<?= e($filters['q']) ?>" placeholder="Cliente, tracking, mensagem"></div><div class="col-md-3"><label class="form-label fw-semibold">Publicado</label><select name="published" class="form-select"><option value="">Todos</option><option value="1" <?= (string) $filters['published'] === '1' ? 'selected' : '' ?>>Sim</option><option value="0" <?= (string) $filters['published'] === '0' ? 'selected' : '' ?>>Não</option></select></div><div class="col-md-2"><label class="form-label fw-semibold">Nota</label><select name="rating" class="form-select"><option value="">Todas</option><?php for ($i = 5; $i >= 1; $i--): ?><option value="<?= $i ?>" <?= $filters['rating'] === (string) $i ? 'selected' : '' ?>><?= $i ?></option><?php endfor; ?></select></div><div class="col-md-2 d-grid"><label class="form-label">&nbsp;</label><button class="btn btn-primary"><i class="fa-solid fa-filter me-2"></i>Filtrar</button></div></form></div>
<div class="row g-4"><?php foreach ($feedbacks as $feedback): ?><div class="col-lg-6"><div class="feedback-card"><div class="d-flex justify-content-between align-items-start mb-3"><div class="d-flex gap-3 align-items-center"><span class="feature-icon"><i class="fa-solid fa-user-circle"></i></span><div><div class="fw-semibold"><?= e($feedback['client_name']) ?></div><div class="small text-muted">Pedido <?= e($feedback['tracking_code']) ?> · <?= e($feedback['order_status']) ?></div></div></div><span class="badge text-bg-warning rounded-pill"><?= e((string) $feedback['rating']) ?>/5</span></div><div class="rating-stars mb-3"><?php for ($i = 0; $i < (int) $feedback['rating']; $i++): ?><i class="fa-solid fa-star"></i><?php endfor; ?></div><p class="mb-3"><?= e($feedback['message']) ?></p><div class="d-flex justify-content-between align-items-center"><span class="small text-muted"><?= e($feedback['created_at']) ?></span><form method="post" action="/admin/feedbacks/<?= e((string) $feedback['id']) ?>/toggle-publicacao"><?= \App\Core\Csrf::field() ?><button class="btn btn-outline-primary btn-sm"><i class="fa-solid fa-bullhorn me-2"></i><?= $feedback['is_published'] ? 'Despublicar' : 'Publicar' ?></button></form></div></div></div><?php endforeach; ?></div>
